SELECT num_reviews
FROM reviewer_stats
WHERE reviewer_id = 1;

SELECT num_reviews 
FROM top_reviewers 
WHERE num_reviews > 50;

SELECT avg_rating AS average_rating, num_reviews
FROM product_stats
WHERE product_id = 0;

SELECT COUNT(DISTINCT r.reviewer_id) 
FROM reviewers r
JOIN reviews rv ON r.reviewer_id = rv.reviewer_id;

SELECT name
FROM reviewers
WHERE reviewer_id IN (SELECT reviewer_id FROM reviews);

SELECT COUNT(sentiment_id) AS sentiment_count
FROM reviewer_sentiment
WHERE reviewer_id = 1;
